1	import { useState } from "react";
2	import { signup, login, ApiError } from "../api.ts";
3	import { storeAuth } from "../authStore.ts";
4	
5	interface AuthProps {
6	  initialMode: "login" | "signup";
7	  onAuth: () => void;
8	}
9	
10	export default function Auth({ initialMode, onAuth }: AuthProps) {
11	  const [mode, setMode] = useState<"login" | "signup">(initialMode);
12	  const [username, setUsername] = useState("");
13	  const [email, setEmail] = useState("");
14	  const [password, setPassword] = useState("");
15	  const [error, setError] = useState("");
16	  const [loading, setLoading] = useState(false);
17	
18	  const handleSubmit = async (e: React.FormEvent) => {
19	    e.preventDefault();
20	    setError("");
21	    setLoading(true);
22	    try {
23	      if (mode === "signup") {
24	        const res = await signup({ username, email, password });
25	        storeAuth(res.token, res.user);
26	      } else {
27	        const res = await login({ username, password });
28	        storeAuth(res.token, res.user);
29	      }
30	      onAuth();
31	    } catch (err) {
32	      if (err instanceof ApiError) {
33	        const messages: Record<string, string> = {
34	          username_taken: "That username is already taken.",
35	          email_taken: "That email is already in use.",
36	          invalid_credentials: "Wrong username or password.",
37	        };
38	        setError(messages[err.code] || err.code);
39	      } else {
40	        setError("Network error. Please try again.");
41	      }
42	    } finally {
43	      setLoading(false);
44	    }
45	  };
46	
47	  return (
48	    <div style={s.page}>
49	      <div style={s.card}>
50	        <div style={s.logoRow}>
51	          <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="#5b5bff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
52	            <rect x="3" y="3" width="18" height="18" rx="3" />
53	            <path d="M8 16l3-8 3 8" />
54	            <path d="M16 8v8" />
55	          </svg>
56	          <span style={s.logoText}>Whiteboard</span>
57	        </div>
58	
59	        <h2 style={s.heading}>
60	          {mode === "login" ? "Welcome back" : "Create account"}
61	        </h2>
62	        <p style={s.subheading}>
63	          {mode === "login"
64	            ? "Sign in to your workspace"
65	            : "Get started with collaborative drawing"}
66	        </p>
67	
68	        <form onSubmit={handleSubmit} style={s.form}>
69	          <div style={s.field}>
70	            <label style={s.label}>Username</label>
71	            <input
72	              style={s.input}
73	              type="text"
74	              value={username}
75	              onChange={(e) => setUsername(e.target.value)}
76	              required
77	              autoComplete="username"
78	              placeholder="your-username"
79	            />
80	          </div>
81	
82	          {mode === "signup" && (
83	            <div style={s.field}>
84	              <label style={s.label}>Email</label>
85	              <input
86	                style={s.input}
87	                type="email"
88	                value={email}
89	                onChange={(e) => setEmail(e.target.value)}
90	                required
91	                autoComplete="email"
92	                placeholder="you@example.com"
93	              />
94	            </div>
95	          )}
96	
97	          <div style={s.field}>
98	            <label style={s.label}>Password</label>
99	            <input
100	              style={s.input}
101	              type="password"
102	              value={password}
103	              onChange={(e) => setPassword(e.target.value)}
104	              required
105	              minLength={4}
106	              autoComplete={mode === "signup" ? "new-password" : "current-password"}
107	              placeholder="Min. 4 characters"
108	            />
109	          </div>
110	
111	          {error && <div style={s.error}>{error}</div>}
112	
113	          <button type="submit" style={s.submit} disabled={loading}>
114	            {loading ? "Please wait..." : mode === "login" ? "Sign in" : "Create account"}
115	          </button>
116	        </form>
117	
118	        <div style={s.divider}>
119	          <span style={s.dividerLine} />
120	          <span style={s.dividerText}>or</span>
121	          <span style={s.dividerLine} />
122	        </div>
123	
124	        <button
125	          style={s.switchBtn}
126	          onClick={() => { setMode(mode === "login" ? "signup" : "login"); setError(""); }}
127	        >
128	          {mode === "login" ? "Create a new account" : "Sign in to existing account"}
129	        </button>
130	      </div>
131	    </div>
132	  );
133	}
