1	import { useState, useEffect } from "react";
2	import type { CanvasSummary } from "../types.ts";
3	import { getCanvases, createCanvas, ApiError } from "../api.ts";
4	import { clearAuth, getStoredUser } from "../authStore.ts";
5	
6	interface CanvasListProps {
7	  onSelectCanvas: (canvasId: string) => void;
8	  onLogout: () => void;
9	}
10	
11	export default function CanvasList({
12	  onSelectCanvas,
13	  onLogout,
14	}: CanvasListProps) {
15	  const [canvases, setCanvases] = useState<CanvasSummary[]>([]);
16	  const [newName, setNewName] = useState("");
17	  const [loading, setLoading] = useState(true);
18	  const [error, setError] = useState("");
19	  const [creating, setCreating] = useState(false);
20	  const user = getStoredUser();
21	
22	  useEffect(() => {
23	    let cancelled = false;
24	    getCanvases()
25	      .then((data) => {
26	        if (!cancelled) {
27	          setCanvases(data);
28	          setLoading(false);
29	        }
30	      })
31	      .catch((err) => {
32	        if (!cancelled) {
33	          if (err instanceof ApiError && err.status === 401) {
34	            handleLogout();
35	          } else {
36	            setError("Failed to load canvases.");
37	            setLoading(false);
38	          }
39	        }
40	      });
41	    return () => { cancelled = true; };
42	    // eslint-disable-next-line react-hooks/exhaustive-deps
43	  }, []);
44	
45	  const handleLogout = () => {
46	    clearAuth();
47	    onLogout();
48	  };
49	
50	  const handleCreate = async (e: React.FormEvent) => {
51	    e.preventDefault();
52	    if (!newName.trim()) return;
53	    setCreating(true);
54	    setError("");
55	    try {
56	      const canvas = await createCanvas({ name: newName.trim() });
57	      setCanvases((prev) => [canvas, ...prev]);
58	      setNewName("");
59	    } catch (err) {
60	      if (err instanceof ApiError && err.status === 401) {
61	        handleLogout();
62	      } else {
63	        setError("Failed to create canvas.");
64	      }
65	    } finally {
66	      setCreating(false);
67	    }
68	  };
69	
70	  return (
71	    <div style={s.page}>
72	      <div style={s.container}>
73	        {/* Header */}
74	        <div style={s.header}>
75	          <div>
76	            <h1 style={s.title}>Your Canvases</h1>
77	            <p style={s.subtitle}>
78	              {user?.username ? `Signed in as ${user.username}` : ""}
79	            </p>
80	          </div>
81	          <button style={s.logoutBtn} onClick={handleLogout}>
82	            Sign out
83	          </button>
84	        </div>
85	
86	        {/* Create form */}
87	        <form onSubmit={handleCreate} style={s.createForm}>
88	          <input
89	            style={s.input}
90	            type="text"
91	            placeholder="New canvas name..."
92	            value={newName}
93	            onChange={(e) => setNewName(e.target.value)}
94	            required
95	          />
96	          <button type="submit" style={s.createBtn} disabled={creating}>
97	            {creating ? "..." : "Create"}
98	          </button>
99	        </form>
100	
101	        {error && <div style={s.error}>{error}</div>}
102	
103	        {/* Canvas grid */}
104	        {loading ? (
105	          <p style={s.empty}>Loading...</p>
106	        ) : canvases.length === 0 ? (
107	          <div style={s.emptyState}>
108	            <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#c5c6d0" strokeWidth="1.5" strokeLinecap="round">
109	              <rect x="3" y="3" width="18" height="18" rx="3" />
110	              <path d="M8 12h8M12 8v8" />
111	            </svg>
112	            <p style={s.emptyText}>No canvases yet. Create one above.</p>
113	          </div>
114	        ) : (
115	          <div style={s.grid}>
116	            {canvases.map((c) => (
117	              <button
118	                key={c.id}
119	                style={s.card}
120	                onClick={() => onSelectCanvas(c.id)}
121	                onMouseEnter={(e) => {
122	                  (e.currentTarget as HTMLElement).style.borderColor = "#5b5bff";
123	                  (e.currentTarget as HTMLElement).style.transform = "translateY(-2px)";
124	                }}
125	                onMouseLeave={(e) => {
126	                  (e.currentTarget as HTMLElement).style.borderColor = "#e4e5eb";
127	                  (e.currentTarget as HTMLElement).style.transform = "none";
128	                }}
129	              >
130	                <div style={s.cardPreview}>
131	                  <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#b0b3c4" strokeWidth="1.5" strokeLinecap="round">
132	                    <rect x="4" y="4" width="7" height="7" rx="1" />
133	                    <circle cx="17" cy="7" r="3" />
134	                    <path d="M4 17l5 3 5-3 6 3" />
135	                  </svg>
136	                </div>
137	                <div style={s.cardBody}>
138	                  <span style={s.cardName}>{c.name}</span>
139	                  <span style={s.cardDate}>
140	                    {new Date(c.createdAt).toLocaleDateString(undefined, {
141	                      month: "short",
142	                      day: "numeric",
143	                    })}
144	                  </span>
145	                </div>
146	              </button>
147	            ))}
148	          </div>
149	        )}
150	      </div>
151	    </div>
152	  );
153	}
