1	import { useState } from "react";
2	import type { PresenceUser } from "../types.ts";
3	import { inviteToCanvas, ApiError } from "../api.ts";
4	
5	interface InvitePanelProps {
6	  canvasId: string;
7	  onlineUsers: PresenceUser[];
8	}
9	
10	export default function InvitePanel({ canvasId, onlineUsers }: InvitePanelProps) {
11	  const [identifier, setIdentifier] = useState("");
12	  const [message, setMessage] = useState("");
13	  const [messageType, setMessageType] = useState<"success" | "error">("success");
14	  const [sending, setSending] = useState(false);
15	  const [showInvite, setShowInvite] = useState(false);
16	
17	  const handleInvite = async (e: React.FormEvent) => {
18	    e.preventDefault();
19	    if (!identifier.trim()) return;
20	    setSending(true);
21	    setMessage("");
22	    try {
23	      await inviteToCanvas(canvasId, { identifier: identifier.trim() });
24	      setMessage("Invited!");
25	      setMessageType("success");
26	      setIdentifier("");
27	      setTimeout(() => setMessage(""), 2000);
28	    } catch (err) {
29	      if (err instanceof ApiError) {
30	        const messages: Record<string, string> = {
31	          user_not_found: "User not found.",
32	          canvas_not_found: "Canvas not found.",
33	          not_a_member: "Not a member.",
34	        };
35	        setMessage(messages[err.code] || err.code);
36	      } else {
37	        setMessage("Failed to invite.");
38	      }
39	      setMessageType("error");
40	    } finally {
41	      setSending(false);
42	    }
43	  };
44	
45	  return (
46	    <div style={s.wrapper}>
47	      {/* User avatars — always visible */}
48	      <div style={s.avatarRow}>
49	        {onlineUsers.map((u) => (
50	          <div
51	            key={u.userId}
52	            title={u.username}
53	            style={{
54	              ...s.avatar,
55	              background: u.color,
56	            }}
57	          >
58	            {u.username.charAt(0).toUpperCase()}
59	          </div>
60	        ))}
61	        <button
62	          style={s.inviteBtn}
63	          onClick={() => setShowInvite(!showInvite)}
64	          title="Invite collaborator"
65	        >
66	          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round">
67	            <path d="M12 5v14M5 12h14" />
68	          </svg>
69	        </button>
70	      </div>
71	
72	      {/* Invite dropdown */}
73	      {showInvite && (
74	        <div style={s.dropdown}>
75	          <div style={s.dropdownHeader}>Invite to canvas</div>
76	          <form onSubmit={handleInvite} style={s.form}>
77	            <input
78	              style={s.input}
79	              type="text"
80	              placeholder="Username or email"
81	              value={identifier}
82	              onChange={(e) => setIdentifier(e.target.value)}
83	              required
84	              autoFocus
85	            />
86	            <button type="submit" style={s.sendBtn} disabled={sending}>
87	              {sending ? "..." : "Send"}
88	            </button>
89	          </form>
90	          {message && (
91	            <div style={{
92	              ...s.msg,
93	              color: messageType === "error" ? "#e03131" : "#2b8a3e",
94	              background: messageType === "error" ? "#fff5f5" : "#ebfbee",
95	            }}>
96	              {message}
97	            </div>
98	          )}
99	        </div>
100	      )}
101	    </div>
102	  );
103	}
104	
