16	const HANDLE_SIZE = 8;
17	
18	export function renderScene(
19	  ctx: CanvasRenderingContext2D,
20	  shapes: Shape[],
21	  selection: SelectionState | null,
22	  cursors: Map<string, CursorInfo>,
23	  previewShape: Shape | null,
24	  canvasWidth: number,
25	  canvasHeight: number,
26	  dpr: number
27	): void {
28	  ctx.save();
29	  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
30	
31	  // Background
32	  ctx.fillStyle = "#f8f9fb";
33	  ctx.fillRect(0, 0, canvasWidth, canvasHeight);
34	
35	  // Dot grid
36	  ctx.fillStyle = "#d4d5db";
37	  const gridSpacing = 20;
38	  const dotSize = 1;
39	  for (let gx = gridSpacing; gx < canvasWidth; gx += gridSpacing) {
40	    for (let gy = gridSpacing; gy < canvasHeight; gy += gridSpacing) {
41	      ctx.fillRect(gx - dotSize / 2, gy - dotSize / 2, dotSize, dotSize);
42	    }
43	  }
44	
45	  // Draw shapes with selected shape rendered last (on top) for visual "lift"
46	  const selectedShapeId = selection?.shapeId ?? null;
47	  let selectedShape: Shape | null = null;
48	
49	  for (const shape of shapes) {
50	    if (shape.id === selectedShapeId) {
51	      selectedShape = shape;
52	      continue; // skip — will draw last
53	    }
54	    drawShape(ctx, shape);
55	  }
56	
57	  // Draw selected shape on top of all others
58	  if (selectedShape) {
59	    drawShape(ctx, selectedShape);
60	  }
61	
62	  // Draw preview shape
63	  if (previewShape) {
64	    drawShape(ctx, previewShape);
65	  }
66	
67	  // Draw selection box over the (already-drawn) selected shape
68	  if (selection && selectedShape) {
69	    drawSelectionBox(ctx, selectedShape);
70	  }
71	
72	  // Draw remote cursors
73	  for (const [, cursor] of cursors) {
74	    drawCursor(ctx, cursor);
75	  }
76	
77	  ctx.restore();
78	}
