80	function drawShape(ctx: CanvasRenderingContext2D, shape: Shape): void {
81	  ctx.save();
82	  ctx.fillStyle = shape.fill || "transparent";
83	  ctx.strokeStyle = shape.stroke || "#000000";
84	  ctx.lineWidth = shape.strokeWidth;
85	
86	  switch (shape.type) {
87	    case "rectangle":
88	      if (shape.fill) {
89	        ctx.fillRect(shape.x, shape.y, shape.width, shape.height);
90	      }
91	      ctx.strokeRect(shape.x, shape.y, shape.width, shape.height);
92	      break;
93	
94	    case "ellipse": {
95	      const cx = shape.x + shape.width / 2;
96	      const cy = shape.y + shape.height / 2;
97	      const rx = Math.abs(shape.width / 2);
98	      const ry = Math.abs(shape.height / 2);
99	      ctx.beginPath();
100	      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
101	      if (shape.fill) {
102	        ctx.fill();
103	      }
104	      ctx.stroke();
105	      break;
106	    }
107	
108	    case "line":
109	      ctx.beginPath();
110	      ctx.moveTo(shape.x, shape.y);
111	      ctx.lineTo(shape.x + shape.width, shape.y + shape.height);
112	      ctx.stroke();
113	      break;
114	
115	    case "text": {
116	      const fontSize = shape.fontSize || 16;
117	      ctx.font = `${fontSize}px sans-serif`;
118	      ctx.fillStyle = shape.fill || "#000000";
119	      ctx.fillText(shape.text || "", shape.x, shape.y + fontSize);
120	      if (shape.stroke && shape.strokeWidth > 0) {
121	        ctx.strokeStyle = shape.stroke;
122	        ctx.lineWidth = shape.strokeWidth;
123	        ctx.strokeText(shape.text || "", shape.x, shape.y + fontSize);
124	      }
125	      break;
126	    }
127	  }
128	
129	  ctx.restore();
130	}
131	
132	function drawSelectionBox(ctx: CanvasRenderingContext2D, shape: Shape): void {
133	  ctx.save();
134	  ctx.strokeStyle = "#0088ff";
135	  ctx.lineWidth = 1;
136	  ctx.setLineDash([4, 4]);
137	  ctx.strokeRect(shape.x - 2, shape.y - 2, shape.width + 4, shape.height + 4);
138	  ctx.setLineDash([]);
139	
140	  // Draw handles at corners
141	  const handles = getHandlePositions(shape);
142	  ctx.fillStyle = "#0088ff";
143	  for (const h of handles) {
144	    ctx.fillRect(h.x, h.y, h.w, h.h);
145	  }
146	
147	  ctx.restore();
148	}
149	
150	export function getHandlePositions(
151	  shape: Shape
152	): { x: number; y: number; w: number; h: number; corner: string }[] {
153	  const hs = HANDLE_SIZE;
154	  const half = hs / 2;
155	  return [
156	    { x: shape.x - half - 2, y: shape.y - half - 2, w: hs, h: hs, corner: "nw" },
157	    { x: shape.x + shape.width - half + 2, y: shape.y - half - 2, w: hs, h: hs, corner: "ne" },
158	    { x: shape.x - half - 2, y: shape.y + shape.height - half + 2, w: hs, h: hs, corner: "sw" },
159	    {
160	      x: shape.x + shape.width - half + 2,
161	      y: shape.y + shape.height - half + 2,
162	      w: hs,
163	      h: hs,
164	      corner: "se",
165	    },
166	  ];
167	}
168	
169	function drawCursor(ctx: CanvasRenderingContext2D, cursor: CursorInfo): void {
170	  ctx.save();
171	  ctx.globalAlpha = cursor.opacity ?? 1;
172	
173	  // Draw cursor arrow
174	  ctx.fillStyle = cursor.color;
175	  ctx.strokeStyle = "#ffffff";
176	  ctx.lineWidth = 1;
177	
178	  ctx.beginPath();
179	  ctx.moveTo(cursor.x, cursor.y);
180	  ctx.lineTo(cursor.x, cursor.y + 16);
181	  ctx.lineTo(cursor.x + 5, cursor.y + 12);
182	  ctx.lineTo(cursor.x + 10, cursor.y + 12);
183	  ctx.closePath();
184	  ctx.fill();
185	  ctx.stroke();
186	
187	  // Draw username label
188	  ctx.font = "11px sans-serif";
189	  const metrics = ctx.measureText(cursor.username);
190	  const labelX = cursor.x + 12;
191	  const labelY = cursor.y + 10;
192	  const padding = 3;
193	
194	  ctx.fillStyle = cursor.color;
195	  const rx = labelX - padding;
196	  const ry2 = labelY - 10 - padding;
197	  const rw = metrics.width + padding * 2;
198	  const rh = 14 + padding * 2;
199	  const r = 3;
200	  ctx.beginPath();
201	  ctx.moveTo(rx + r, ry2);
202	  ctx.lineTo(rx + rw - r, ry2);
203	  ctx.arcTo(rx + rw, ry2, rx + rw, ry2 + r, r);
204	  ctx.lineTo(rx + rw, ry2 + rh - r);
205	  ctx.arcTo(rx + rw, ry2 + rh, rx + rw - r, ry2 + rh, r);
206	  ctx.lineTo(rx + r, ry2 + rh);
207	  ctx.arcTo(rx, ry2 + rh, rx, ry2 + rh - r, r);
208	  ctx.lineTo(rx, ry2 + r);
209	  ctx.arcTo(rx, ry2, rx + r, ry2, r);
210	  ctx.closePath();
211	  ctx.fill();
212	
213	  ctx.fillStyle = "#ffffff";
214	  ctx.fillText(cursor.username, labelX, labelY);
215	
216	  ctx.restore();
217	}
218	
219	export function hitTest(shapes: Shape[], x: number, y: number): Shape | null {
220	  // Iterate in reverse z-order (topmost first)
221	  for (let i = shapes.length - 1; i >= 0; i--) {
222	    const s = shapes[i];
223	    if (isPointInShape(s, x, y)) {
224	      return s;
225	    }
226	  }
227	  return null;
228	}
229	
230	function isPointInShape(shape: Shape, px: number, py: number): boolean {
231	  const margin = 4;
232	  switch (shape.type) {
233	    case "rectangle":
234	    case "text":
235	      return (
236	        px >= shape.x - margin &&
237	        px <= shape.x + shape.width + margin &&
238	        py >= shape.y - margin &&
239	        py <= shape.y + shape.height + margin
240	      );
241	
242	    case "ellipse": {
243	      const cx = shape.x + shape.width / 2;
244	      const cy = shape.y + shape.height / 2;
245	      const rx = Math.abs(shape.width / 2) + margin;
246	      const ry = Math.abs(shape.height / 2) + margin;
247	      if (rx === 0 || ry === 0) return false;
248	      const dx = px - cx;
249	      const dy = py - cy;
250	      return (dx * dx) / (rx * rx) + (dy * dy) / (ry * ry) <= 1;
251	    }
252	
253	    case "line": {
254	      // Check distance from point to line segment
255	      const x1 = shape.x;
256	      const y1 = shape.y;
257	      const x2 = shape.x + shape.width;
258	      const y2 = shape.y + shape.height;
259	      const dist = distToSegment(px, py, x1, y1, x2, y2);
260	      return dist <= shape.strokeWidth / 2 + margin + 4;
261	    }
262	
263	    default:
264	      return false;
265	  }
266	}
267	
268	function distToSegment(
269	  px: number,
270	  py: number,
271	  x1: number,
272	  y1: number,
273	  x2: number,
274	  y2: number
275	): number {
276	  const dx = x2 - x1;
277	  const dy = y2 - y1;
278	  const lenSq = dx * dx + dy * dy;
279	  if (lenSq === 0) return Math.sqrt((px - x1) ** 2 + (py - y1) ** 2);
280	  let t = ((px - x1) * dx + (py - y1) * dy) / lenSq;
281	  t = Math.max(0, Math.min(1, t));
282	  const projX = x1 + t * dx;
283	  const projY = y1 + t * dy;
284	  return Math.sqrt((px - projX) ** 2 + (py - projY) ** 2);
285	}
286	
287	export function hitTestHandle(
288	  shape: Shape,
289	  x: number,
290	  y: number
291	): string | null {
292	  const handles = getHandlePositions(shape);
293	  for (const h of handles) {
294	    if (x >= h.x && x <= h.x + h.w && y >= h.y && y <= h.y + h.h) {
295	      return h.corner;
296	    }
297	  }
298	  return null;
299	}
